external_knowledge:
- 'Generational surveys' refer to a type of survey specifically targeting or analyzing generational differences;
- 'response time' is used to determine how quickly respondents have engaged with and completed the survey;
- The average is calculated to understand the typical time it takes for responses to come in.

sql:
SELECT AVG(average_income) 
FROM generational_cohorts 
WHERE cohort_name = 'Older Millennial';

SELECT surveys.survey_name, survey_questions.question_text
FROM surveys
JOIN survey_questions ON surveys.survey_id = survey_questions.survey_id;

SELECT DISTINCT user_name
FROM users
JOIN access_logs ON users.user_id = access_logs.user_id;

SELECT survey_name 
FROM surveys 
WHERE survey_id IN (SELECT survey_id FROM survey_questions);
